import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithSkipHeaderRecordNoArg() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withSkipHeaderRecord();
        assertNotNull(result);
        assertTrue(result.getSkipHeaderRecord());
        // Original instance should remain unchanged (immutability)
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testWithSkipHeaderRecordBooleanTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withSkipHeaderRecord(true);
        assertNotNull(result);
        assertTrue(result.getSkipHeaderRecord());
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testWithSkipHeaderRecordBooleanFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        CSVFormat result = format.withSkipHeaderRecord(false);
        assertNotNull(result);
        assertFalse(result.getSkipHeaderRecord());
        assertTrue(format.getSkipHeaderRecord());
    }
}
